class Solution:
    def numberOfGoodSubarraySplits(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        count_ones = 0
        prev_one = -1
        result = 1

        for i, num in enumerate(nums):
            if num == 1:
                count_ones += 1
                if count_ones > 1:
                    result = (result * (i - prev_one)) % MOD
                prev_one = i

        return result if count_ones > 0 else 0
